"use client";

import { useTheme } from "../context/themeContext";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
);

interface AQICardProps {
  city: string;
  data?: any;
  loading: boolean;
}

export default function AQICard({ city, data, loading }: AQICardProps) {
  const { theme } = useTheme();

  if (loading) return <div>Loading {city}...</div>;
  if (!data) return <div>Data not available for {city}</div>;

  const labels =
    data.forecast?.daily.pm25.map((d: { day?: string }, i: number) =>
      d.day
        ? new Date(d.day).toLocaleDateString("en-US", { weekday: "short" })
        : new Date(Date.now() + i * 86400000).toLocaleDateString("en-US", {
            weekday: "short",
          }),
    ) || [];

  const getAQIColor = (aqi: number) => {
    if (aqi <= 50) return "#22c55e";
    if (aqi <= 100) return "#eab308";
    if (aqi <= 150) return "#f97316";
    if (aqi <= 200) return "#dc2626";
    if (aqi <= 300) return "#7c3aed";
    return "#475569";
  };

  const chartData = {
    labels,
    datasets: [
      {
        label: "PM2.5",
        data:
          data.forecast?.daily.pm25.map((d: { avg: number }) => d.avg) || [],
        backgroundColor: data.forecast?.daily.pm25.map((d: { avg: number }) =>
          getAQIColor(d.avg),
        ),
        borderRadius: 6,
        borderSkipped: false,
      },
    ],
  };

  const chartTextColor = theme === "dark" ? "#fff" : "#000";

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false, labels: { color: chartTextColor } },
      title: {
        display: true,
        text: "5-Day PM2.5 AQI Forecast",
        color: chartTextColor,
      },
      tooltip: {
        callbacks: { label: (ctx: any) => `AQI: ${ctx.raw}` },
        bodyColor: chartTextColor,
        titleColor: chartTextColor,
        backgroundColor:
          theme === "dark" ? "rgba(0,0,0,0.8)" : "rgba(255,255,255,0.9)",
      },
    },
    scales: {
      x: { ticks: { color: chartTextColor } },
      y: { ticks: { color: chartTextColor, stepSize: 50 } },
    },
  };

  return (
    <div className="glass-card w-full box-border transition-all p-4">
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2 mb-4">
        <h2 className="text-2xl font-bold text-left">{city}</h2>
        <div className="flex gap-2 flex-wrap">
          <span className="px-3 py-1 rounded-full text-sm font-medium bg-gray-200 text-black dark:bg-gray-800 dark:text-white">
            AQI: {data.aqi}
          </span>
          <span className="px-3 py-1 rounded-full text-sm font-medium bg-gray-200 text-black dark:bg-gray-800 dark:text-white">
            Dominant: {data.dominentpol}
          </span>
        </div>
      </div>
      <div className="h-48">
        <Bar data={chartData} options={chartOptions} />
      </div>
    </div>
  );
}
