"use client";
import { useEffect, useState } from "react";
import { cityMapping } from "../lib/cityMapping";

export function useAQIData() {
  const cities = Object.keys(cityMapping);
  const [data, setData] = useState<Record<string, any>>({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  const fetchAll = async () => {
    setError(false);
    try {
      const results = await Promise.all(
        cities.map(async (city) => {
          const res = await fetch(`/api/air-quality?city=${city}`);
          const json = await res.json();
          return [city, json];
        }),
      );
      setData(Object.fromEntries(results));
    } catch (err) {
      console.error(err);
      setError(true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAll();
    const interval = setInterval(fetchAll, 30 * 1000); // refresh every 30s
    return () => clearInterval(interval);
  }, []);

  return { data, loading, error };
}
